      CREATE View [SSRS].[CountyCricketBoard_PriorityLeagues_ThisMonth_vw]  as    SELECT [League_ID]        ,CAse When League_ID = 7387 then 'National Village Cup' else [League_Of_Fixture]ENd [League_Of_Fixture]        ,isnull([No Result],0) [No Result]        ,isnull([Abandoned],0) [Abandoned]        ,isnull([Cancelled],0) [Cancelled]        ,isnull([Conceded],0) [Conceded]        ,isnull([InProgress],0) [InProgress]        ,isnull([Win],0) [Win]        ,isnull([ShortSided],0) [ShortSided]    FROM [SSRS].[CountyCricketBoard_PriorityLeagues_ThisMonth]    